import type { MinMax } from '../../core/types/min-max.js';
import {
  XYAxisTypeCategorical,
  XYAxisTypeLinear,
  XYAxisTypeLog,
  XYAxisTypeTime,
} from '../types/axis.js';
import type {
  AxisIdToScaleDomain,
  CategoryName,
  XYChartAxisInternal,
} from '../types/xy-chart-internals.js';
import {
  type AreaDatapoint,
  type BarDatapoint,
  type DotDatapoint,
  type LineDatapoint,
  type RectDatapoint,
  type XYAccessorDataTypes,
} from '../types/xy-chart.js';

function getMinMax(
  axisId: string,
  coordinate0: number,
  coordinate1: number | undefined,
  axisIdToScaleDomain: AxisIdToScaleDomain,
): MinMax {
  const minMax = (axisIdToScaleDomain.get(axisId) ?? {
    min: coordinate0,
    max: coordinate1,
  }) as MinMax;

  const minValues = [minMax.min, coordinate0, coordinate1].filter(
    (value) => value !== undefined,
  );
  const maxValues = [minMax.max, coordinate0, coordinate1].filter(
    (value) => value !== undefined,
  );

  minMax.min = Math.min(...minValues);
  minMax.max = Math.max(...maxValues);

  return minMax;
}

function getCategoricalDomain(
  axisId: string,
  v0: string,
  v1: string,
  axisIdToScaleDomain: AxisIdToScaleDomain,
) {
  const categoricalSet = (axisIdToScaleDomain.get(axisId) ??
    new Set()) as Set<CategoryName>;

  if (v0) {
    categoricalSet.add(v0);
  }
  if (v1) {
    categoricalSet.add(v1);
  }

  return categoricalSet;
}

type CalculateAxesDomainArgs = {
  axisId: string;
  a0: XYAccessorDataTypes | undefined;
  a1: XYAccessorDataTypes | undefined | unknown;
  axisIdToScaleDomain: AxisIdToScaleDomain;
};

type CalculateAxesDomainByType = {
  [XYAxisTypeLinear]: (args: CalculateAxesDomainArgs) => MinMax;
  [XYAxisTypeLog]: (args: CalculateAxesDomainArgs) => MinMax;
  [XYAxisTypeCategorical]: (args: CalculateAxesDomainArgs) => Set<CategoryName>;
  [XYAxisTypeTime]: (args: CalculateAxesDomainArgs) => MinMax;
};

const calculateAxesDomainsMap: CalculateAxesDomainByType = {
  [XYAxisTypeLinear]: (args) => {
    return getMinMax(
      args.axisId,
      args.a0 as number,
      args.a1 as number,
      args.axisIdToScaleDomain,
    );
  },
  [XYAxisTypeLog]: (args) => {
    return getMinMax(
      args.axisId,
      args.a0 as number,
      args.a1 as number,
      args.axisIdToScaleDomain,
    );
  },
  [XYAxisTypeCategorical]: (args) => {
    return getCategoricalDomain(
      args.axisId,
      args.a0 as string,
      args.a1 as string,
      args.axisIdToScaleDomain,
    );
  },
  [XYAxisTypeTime]: (args) => {
    return getMinMax(
      args.axisId,
      args.a0?.valueOf() as number,
      args.a1?.valueOf() as number,
      args.axisIdToScaleDomain,
    );
  },
};

//TODO: types issues, rect and dot series not share the same types, x1 and y1 are working cause of unknown type
export function calculateAxesDomains(
  xAxis: XYChartAxisInternal,
  yAxis: XYChartAxisInternal,
  datapoint:
    | LineDatapoint
    | DotDatapoint
    | BarDatapoint
    | RectDatapoint
    | AreaDatapoint,
  axisIdToScaleDomain: AxisIdToScaleDomain,
  isSeriesVisible: boolean,
) {
  const xDomain = calculateAxesDomainsMap[xAxis.type]({
    axisId: xAxis.id,
    a0: datapoint.x0,
    a1: datapoint.x1,
    axisIdToScaleDomain,
  });

  const yDomain =
    isSeriesVisible || yAxis.type === XYAxisTypeCategorical
      ? calculateAxesDomainsMap[yAxis.type]({
          axisId: yAxis.id,
          a0: datapoint.y0,
          a1: datapoint.y1,
          axisIdToScaleDomain,
        })
      : axisIdToScaleDomain.get(yAxis.id) ?? {};

  return { xDomain, yDomain };
}
